const items = $input.all();
const busqueda = ($('Ejecutar Workflow').first().json.busqueda ?? '').trim();

// Detect empty result
const rows = (items.length === 1 && !items[0].json.property_id) ? [] : items;

if (rows.length === 0) {
  return [{ json: { resultado: `🔍 No se encontraron clientes interesados en "${busqueda}". Verifica el código o la dirección.` } }];
}

// ── Group by property ─────────────────────────────────────────────────────────
const propMap = {};
rows.forEach(it => {
  const r = it.json;
  const pid = r.property_id;
  if (!propMap[pid]) {
    propMap[pid] = {
      code: r.property_code,
      address: r.property_address,
      status: r.property_status,
      clientMap: {}
    };
  }
  // ── Group by client within property ────────────────────────────────────────
  const cid = r.client_id;
  if (!propMap[pid].clientMap[cid]) {
    propMap[pid].clientMap[cid] = {
      name: r.client_name,
      phone: r.phone,
      email: r.email,
      registrations: [],
      notes: []
    };
  }
  propMap[pid].clientMap[cid].registrations.push({
    interest_level: r.interest_level,
    interest_date: r.interest_date,
    notes: r.notes
  });
  if (r.notes) propMap[pid].clientMap[cid].notes.push(r.notes);
});

const levelRank = { 'Muy Alto': 4, 'Alto': 3, 'Medio': 2, 'Bajo': 1 };
const levelEmoji = { 'Muy Alto': '🔥', 'Alto': '⬆️', 'Medio': '➡️', 'Bajo': '⬇️' };

const props = Object.values(propMap);

// Multiple properties → disambiguation
if (props.length > 1) {
  const lista = props.map((p, i) => {
    const uniqueClients = Object.keys(p.clientMap).length;
    return `${i + 1}. *${p.code}* - ${p.address} (${uniqueClients} cliente(s) único(s))`;
  }).join('\n');
  return [{
    json: {
      resultado: `🏠 Encontré ${props.length} inmuebles en "${busqueda}" con interesados:\n\n${lista}\n\n👉 Indícame el código exacto para ver su lista de clientes (ej: 002).`
    }
  }];
}

// Single property → list clients (grouped & consolidated)
const prop = props[0];
const clients = Object.values(prop.clientMap);

// Sort: by highest interest_level then by most registrations
clients.sort((a, b) => {
  const maxA = Math.max(...a.registrations.map(r => levelRank[r.interest_level] || 0));
  const maxB = Math.max(...b.registrations.map(r => levelRank[r.interest_level] || 0));
  if (maxB !== maxA) return maxB - maxA;
  return b.registrations.length - a.registrations.length;
});

const lines = [
  `👥 *Clientes Interesados — Inmueble ${prop.code}*`,
  `📍 ${prop.address} | Estado: ${prop.status}`,
  `Total: ${clients.length} cliente(s) único(s)`,
  ''
];

clients.forEach((c, i) => {
  // Take highest interest level across all registrations
  const maxLevel = c.registrations.reduce((best, r) => {
    return (levelRank[r.interest_level] || 0) > (levelRank[best] || 0) ? r.interest_level : best;
  }, 'Bajo');

  const emoji = levelEmoji[maxLevel] || '•';
  const count = c.registrations.length;
  const countLabel = count > 1 ? ` *(registrado ${count}x — interés elevado)*` : '';

  lines.push(`${i + 1}. ${emoji} *${c.name}*${countLabel}`);
  lines.push(`   📞 ${c.phone}${c.email ? ' | ✉️ ' + c.email : ''}`);
  lines.push(`   Nivel de interés: ${maxLevel}`);

  // Show notes (deduplicated)
  const uniqueNotes = [...new Set(c.notes.filter(Boolean))];
  if (uniqueNotes.length > 0) {
    lines.push(`   💬 ${uniqueNotes.join(' | ')}`);
  }

  lines.push('');
});

return [{ json: { resultado: lines.join('\n') } }];
